// API trả về danh sách câu hỏi, mỗi câu hỏi đã có trường answerCount
import axios from 'axios';

export async function fetchQuestionsWithAnswersCount() {
  const res = await axios.get('http://localhost:8080/api/questions');
  return res.data; // Mỗi object question đã có answerCount
}
